# Fixed weight agreement — agreed by team leads and documented in AI FinOps policy
FIXED_WEIGHTS: dict[str, float] = {
    "platform-eng":   0.40,   # platform team uses shared infra the most
    "data-science":   0.30,
    "cx-product":     0.20,
    "growth":         0.10,
}

assert abs(sum(FIXED_WEIGHTS.values()) - 1.0) < 0.001, "Weights must sum to 1.0"

def fixed_weight_split(pool_cost_usd: float, weights: dict = FIXED_WEIGHTS) -> list[dict]:
    entries = []
    allocated = 0.0
    teams = sorted(weights.items(), key=lambda x: x[1], reverse=True)
    for i, (team, w) in enumerate(teams):
        if i == len(teams) - 1:
            amount = round(pool_cost_usd - allocated, 4)  # absorb rounding
        else:
            amount = round(pool_cost_usd * w, 4)
        allocated += amount
        entries.append({"team": team, "fixed_weight": w, "allocated_cost_usd": amount})
    return entries

def allocate_untagged(
    ledger_df: pd.DataFrame,
    active_teams: list[str],
    method: str = "equal",  # "equal" | "token_weighted"
) -> pd.DataFrame:
    """
    Distribute untagged production costs across active teams.
    'equal' splits evenly — creates equal pressure on all teams to fix tags.
    'token_weighted' scales by team size — proportional but lets small teams hide.
    """
    untagged = ledger_df[
        ledger_df["cost_center"].isna() & (ledger_df["environment"] == "production")
    ]
    total_untagged = untagged["cost_usd"].sum()

    if total_untagged == 0 or not active_teams:
        return pd.DataFrame()

    if method == "equal":
        per_team = round(total_untagged / len(active_teams), 4)
        return pd.DataFrame([
            {"team": t, "allocated_cost_usd": per_team, "reason": "untagged_equal_split"}
            for t in active_teams
        ])

    elif method == "token_weighted":
        team_tokens = ledger_df[
            ledger_df["team"].isin(active_teams)
        ].groupby("team")["input_tokens"].sum()
        total_tokens = team_tokens.sum()
        rows = []
        for team in active_teams:
            share = team_tokens.get(team, 0) / total_tokens if total_tokens > 0 else 1 / len(active_teams)
            rows.append({"team": team, "allocated_cost_usd": round(total_untagged * share, 4),
                         "reason": "untagged_token_weighted"})
        return pd.DataFrame(rows)
